import express from "express";
import { getCategorySummaryController, getMonthlySummaryController, getRecentTransController, getTransSummaryController } from "./dashboard.controller.js";
import { isAuth } from "../../middleware/isAuth.js";
import { authorizeRoles } from "../../middleware/roleAuth.js";
const router = express.Router();
router.get("/summary", isAuth, authorizeRoles("ADMIN", "ANALYST"), getTransSummaryController);
router.get("/categories", isAuth, authorizeRoles("ADMIN", "ANALYST"), getCategorySummaryController);
router.get("/monthly", isAuth, authorizeRoles("ADMIN", "ANALYST"), getMonthlySummaryController);
router.get("/recent-transaction", isAuth, authorizeRoles("ADMIN", "ANALYST"), getRecentTransController);
export default router;
